state_re = re.compile(r',\s*([A-Z]{2})(?:[,\.\s]|$)')

def extract_state(desc):
    if not isinstance(desc, str):
        return None
    m = state_re.search(desc)
    if m:
        return m.group(1)
    # fallback: any two-letter uppercase token
    m2 = re.search(r"\b([A-Z]{2})\b", desc)
    if m2:
        return m2.group(1)
    return None

